import { useState } from "react";

const App = () => {
  const [selected, setSelected] = useState({});

  // Fixed data for V1
  const questions = [
    {
      id: 1,
      question: "Which sensor is specifically designed to measure sound intensity in decibels (dB)?",
      options: ["PIR Sensor", "Analog SPL Meter", "LDR", "DHT11"]
    },
    {
      id: 2,
      question: "Which technology allows a presence detector to sense a person even if they are standing still?",
      options: ["Ultrasonic Sensor", "Passive Infrared (PIR)", "mmWave Radar", "Photoresistor"]
    }
  ];

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  const handleSubmit = () => {
    if (Object.keys(selected).length < 2) {
      alert("Please answer both questions before submitting.");
      return;
    }
    console.log("Answers saved for V2 Score Calculation:", selected);
    alert("V1 Complete: Quiz Submitted!");
  };

  return (
    <div style={styles.container}>
      <div style={styles.wrapper}>

        <header style={styles.header}>
          <div>
            <h1 style={styles.logo}>QUIZZLY <span style={styles.vTag}>V1</span></h1>
            <p style={styles.user}>Harshith B • 23MIS0012</p>
          </div>
          <div style={styles.status}>CORE MODULE</div>
        </header>

        <div style={styles.quizArea}>
          {questions.map((q) => (
            <div key={q.id} style={styles.qCard}>
              <h2 style={styles.qTitle}><span style={styles.qNum}>{q.id}.</span> {q.question}</h2>
              <div style={styles.optGrid}>
                {q.options.map((opt) => {
                  const isActive = selected[q.id] === opt;
                  return (
                    <button
                      key={opt}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{ ...styles.optBtn, ...(isActive ? styles.optActive : {}) }}
                    >
                      <div style={{ ...styles.dot, borderColor: isActive ? "#6366f1" : "#334155" }}>
                        {isActive && <div style={styles.dotInner} />}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        <footer style={styles.footer}>
          <p style={styles.hint}>Ensure all fields are selected to proceed to V2.</p>
          <button onClick={handleSubmit} style={styles.submitBtn}>
            Submit Quiz
          </button>
        </footer>
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#020617",
    color: "#f1f5f9",
    fontFamily: "'Inter', sans-serif",
    display: "flex",
    justifyContent: "center",
    overflow: "hidden", 
  },
  wrapper: {
    width: "100%",
    maxWidth: "900px",
    display: "flex",
    flexDirection: "column",
    padding: "30px",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "20px",
    paddingBottom: "15px",
    borderBottom: "1px solid #1e293b"
  },
  logo: { fontSize: "20px", fontWeight: "900", margin: 0 },
  vTag: { color: "#6366f1", fontSize: "12px" },
  user: { fontSize: "12px", color: "#64748b", margin: "2px 0 0 0" },
  status: { fontSize: "10px", fontWeight: "bold", color: "#6366f1", border: "1px solid #6366f1", padding: "4px 10px", borderRadius: "20px" },

  quizArea: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    gap: "20px",
  },
  qCard: {
    flex: 1,
    background: "rgba(15, 23, 42, 0.6)",
    border: "1px solid #1e293b",
    borderRadius: "16px",
    padding: "25px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center"
  },
  qNum: { color: "#6366f1", marginRight: "8px" },
  qTitle: { fontSize: "18px", margin: "0 0 20px 0", fontWeight: "600", lineHeight: "1.4" },

  optGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" },
  optBtn: {
    all: "unset",
    padding: "14px 18px",
    background: "#1e293b40",
    border: "1px solid #1e293b",
    borderRadius: "12px",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    fontSize: "14px",
    transition: "0.2s"
  },
  optActive: { borderColor: "#6366f1", background: "rgba(99, 102, 241, 0.1)" },
  dot: { width: "14px", height: "14px", border: "2px solid", borderRadius: "50%", marginRight: "12px", display: "flex", alignItems: "center", justifyContent: "center" },
  dotInner: { width: "7px", height: "7px", background: "#6366f1", borderRadius: "50%" },

  footer: {
    marginTop: "20px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
  },
  hint: { fontSize: "12px", color: "#64748b", margin: 0 },
  submitBtn: {
    all: "unset",
    background: "linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)",
    padding: "14px 40px",
    borderRadius: "12px",
    fontWeight: "bold",
    cursor: "pointer",
    boxShadow: "0 10px 20px -5px rgba(99, 102, 241, 0.4)",
  }
};

export default App;
